SELECT r.message_id AS messageId, r.emoji AS emoji, COUNT(1) AS count, MAX(CASE WHEN r.user_id = #{viewerUserId} THEN 1 ELSE 0 END) = 1 AS reacted FROM im_message_reaction r WHERE r.message_id IN
#{messageId}
GROUP BY r.message_id, r.emoji ORDER BY r.message_id ASC, COUNT(1) DESC, r.emoji ASC
